  ('dietitian-moex-11586', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列胺基酸中何者為ketogenic而非glucogenic？ Ile  Leu  Phe  Tyr', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11587', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '胺基酸之R-group上沒有羥基者是： Ser  Tyr  Trp  Thr', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11588', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在膠原蛋白質 (collagen) 中發生羥基化 (hydroxylation) 修飾作用的胺基酸殘基是： 組織胺酸 (His) 和天冬醯胺酸 (Asn)  脯胺酸 (Pro) 和離胺酸 (Lys) 丙胺酸 (Ala) 和白胺酸 (Leu)  半胱胺酸 (Cys) 和甲硫胺酸 (Met)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11589', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關蛋白質二級結構中α-helix及β-sheet之敘述，何者正確？ 連續兩胺基酸殘基之距離在α-helix中大於β-sheet中 離子鍵是維持這兩種二級結構最主要之引力 脯胺酸及甘胺酸殘基可存在α-helix和β-sheet結構中 在α-helix中氫鍵方向與α-helix之走向平行，而在β-sheet中氫鍵β-sheet之走向則為垂直', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11590', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列那一TCA cycle的中間產物可直接參與Heme的合成？ 異檸檬酸  (isocitrate)  反丁烯二酸 (fumarate)  琥珀醯 A (succinyl CoA)  蘋果酸 (malate)', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11591', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列有關DNA雙螺旋結構的敘述何者有誤？ DNA螺旋的兩股其配對鹼基對之間以氫鍵結合 加熱DNA水溶液可以瓦解此DNA雙螺旋結構 加酸或鹼到DNA水溶液可以瓦解此DNA雙螺旋結構 當DNA雙螺旋結構瓦解成單股時，其紫外光的吸光值會減少', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11592', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '在體內DNA的胞嘧啶 (cytosine) 會自然產生去胺作用 (deamination) 變成uracil，此自然產生的胞嘧啶去胺作用，若 沒有適當的修復會造成基因突變，下列何種酵素主要負責此修復工作？ Uracil-DNA glycosylase  DNA photolyases  ABC excinuclease  DNA methyltransferase', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11593', 'dietitian', 'dietitian-moex-092-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', 'DNA複製時，有關新DNA的合成，下列敘述何者正確？ 以5’→3’合成    以3’→5’合成 一股以5’→3’，另一股以3’→5’合成  以5’→3’或3’→5’合成皆可', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "bcdc485a920f", "answer_pdf_sha1": "03a562c0665c", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "111", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
